const fs = require\('fs'\);
const content = fs.readFileSync\('D:/stringsn88keys/whyboot/sleepstudy-report.html', 'utf8'\);
const start = content.indexOf\('var LocalSprData = {'\) + 'var LocalSprData = '.length;
let depth = 0, end = start;
for \(let i = start; i < content.length; i++\) {
    if \(content[i] === '{'\) depth++;
    else if \(content[i] === '}'\) { depth--; if \(depth === 0\) { end = i+1; break; } }
